     1â†’import { Logger } from '@nestjs/common';
     2â†’import { Command, CommandRunner, Option } from 'nest-commander';
     3â†’
     4â†’import { RedshiftTrendingItemsService } from '@modules/db/redshift/trending-items/redshift-trending-items.service';
     5â†’
     6â†’import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
     7â†’
     8â†’interface PopulateTrendingItemsOptions {
     9â†’	startYear?: number;
    10â†’	endYear?: number;
    11â†’	months?: string;
    12â†’	lastWeek?: boolean;
    13â†’}
    14â†’
    15â†’@Command({
    16â†’	name: 'populate-trending-items',
    17â†’	description: 'Fetch order data from Redshift and populate product_annual_sales table',
    18â†’})
    19â†’export class PopulateTrendingItemsCommand extends CommandRunner {
    20â†’	private readonly logger = new Logger(PopulateTrendingItemsCommand.name);
    21â†’	private isShuttingDown = false;
    22â†’	private currentOperation: Promise<void> | null = null;
    23â†’
    24â†’	constructor(
    25â†’		private readonly redshiftTrendingItemsService: RedshiftTrendingItemsService,
    26â†’	) {
    27â†’		super();
    28â†’		this.setupGracefulShutdown();
    29â†’	}
    30â†’
    31â†’	@CronJobExecution({ jobName: 'populate-trending-items' })
    32â†’	async run(
    33â†’		_passedParams: string[],
    34â†’		options: PopulateTrendingItemsOptions,
    35â†’	): Promise<void> {
    36â†’		if (this.isShuttingDown) {
    37â†’			this.logger.warn('Command cancelled due to shutdown signal');
    38â†’			return;
    39â†’		}
    40â†’
    41â†’		try {
    42â†’			this.redshiftTrendingItemsService.resetCancellation();
    43â†’
    44â†’			if (options.lastWeek) {
    45â†’				this.logger.log('Processing last week data for cron job');
    46â†’				this.currentOperation =
    47â†’					this.redshiftTrendingItemsService.fetchAndProcessLastWeekData();
    48â†’				await this.currentOperation;
    49â†’				this.logger.log('Successfully updated trending items with last week data');
    50â†’				return;
    51â†’			}
    52â†’
    53â†’			const currentYear = new Date().getFullYear();
    54â†’			const startYear = options.startYear ?? currentYear - 5;
    55â†’			const endYear = options.endYear ?? currentYear;
    56â†’
    57â†’			let monthsToProcess: number[] | undefined;
    58â†’			if (options.months) {
    59â†’				monthsToProcess = options.months.split(',').map((m) => parseInt(m.trim(), 10));
    60â†’				if (monthsToProcess.some((m) => isNaN(m) || m < 1 || m > 12)) {
    61â†’					throw new Error('Invalid month values. Months must be between 1 and 12.');
    62â†’				}
    63â†’			}
    64â†’
    65â†’			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    66â†’			if (this.isShuttingDown) {
    67â†’				this.logger.warn('Command cancelled due to shutdown signal');
    68â†’				return;
    69â†’			}
    70â†’
    71â†’			this.logger.log(
    72â†’				`Starting to populate trending items data from ${startYear} to ${endYear}`,
    73â†’			);
    74â†’
    75â†’			if (monthsToProcess) {
    76â†’				this.logger.log(`Processing only months: ${monthsToProcess.join(', ')}`);
    77â†’			}
    78â†’
    79â†’			this.currentOperation = this.redshiftTrendingItemsService.fetchAndProcessOrderData({
    80â†’				startYear,
    81â†’				endYear,
    82â†’				...(monthsToProcess && { monthsToProcess }),
    83â†’			});
    84â†’
    85â†’			await this.currentOperation;
    86â†’
    87â†’			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    88â†’			if (!this.isShuttingDown) {
    89â†’				this.logger.log('Successfully populated trending items data');
    90â†’				return;
    91â†’			}
    92â†’		} catch (error) {
    93â†’			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    94â†’			if (this.isShuttingDown) {
    95â†’				this.logger.warn('Command interrupted during shutdown');
    96â†’				return;
    97â†’			}
    98â†’			this.logger.error(`Failed to populate trending items: ${(error as Error).message}`);
    99â†’			process.exit(1);
   100â†’		} finally {
   101â†’			this.currentOperation = null;
   102â†’		}
   103â†’	}
   104â†’
   105â†’	@Option({
   106â†’		flags: '-s, --start-year <startYear>',
   107â†’		description: 'Start year for data fetching (default: 5 years ago)',
   108â†’	})
   109â†’	parseStartYear(value: string): number {
   110â†’		const year = parseInt(value, 10);
   111â†’		if (isNaN(year) || year < 1900 || year > 2100) {
   112â†’			throw new Error('Invalid start year');
   113â†’		}
   114â†’		return year;
   115â†’	}
   116â†’
   117â†’	@Option({
   118â†’		flags: '-e, --end-year <endYear>',
   119â†’		description: 'End year for data fetching (default: current year)',
   120â†’	})
   121â†’	parseEndYear(value: string): number {
   122â†’		const year = parseInt(value, 10);
   123â†’		if (isNaN(year) || year < 1900 || year > 2100) {
   124â†’			throw new Error('Invalid end year');
   125â†’		}
   126â†’		return year;
   127â†’	}
   128â†’
   129â†’	@Option({
   130â†’		flags: '-m, --months <months>',
   131â†’		description:
   132â†’			'Comma-separated list of months to process (1-12). If not specified, all months are processed',
   133â†’	})
   134â†’	parseMonths(value: string): string {
   135â†’		return value;
   136â†’	}
   137â†’
   138â†’	@Option({
   139â†’		flags: '-w, --last-week',
   140â†’		description: 'Process only last week data (for cron jobs)',
   141â†’	})
   142â†’	parseLastWeek(): boolean {
   143â†’		return true;
   144â†’	}
   145â†’
   146â†’	private setupGracefulShutdown(): void {
   147â†’		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   148â†’
   149â†’		signals.forEach((signal) => {
   150â†’			process.on(signal, () => {
   151â†’				void this.handleShutdown(signal);
   152â†’			});
   153â†’		});
   154â†’
   155â†’		process.on('uncaughtException', (error) => {
   156â†’			this.logger.error(`Uncaught exception: ${error.message}`);
   157â†’			void this.handleShutdown('SIGTERM');
   158â†’		});
   159â†’
   160â†’		process.on('unhandledRejection', (reason) => {
   161â†’			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   162â†’			void this.handleShutdown('SIGTERM');
   163â†’		});
   164â†’	}
   165â†’
   166â†’	private async handleShutdown(signal: string): Promise<void> {
   167â†’		if (this.isShuttingDown) {
   168â†’			this.logger.warn('Force shutdown requested, exiting immediately');
   169â†’			process.exit(1);
   170â†’		}
   171â†’
   172â†’		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   173â†’		this.isShuttingDown = true;
   174â†’
   175â†’		this.redshiftTrendingItemsService.cancelOperation();
   176â†’
   177â†’		try {
   178â†’			if (this.currentOperation) {
   179â†’				this.logger.log('Waiting for current operation to complete...');
   180â†’
   181â†’				const shutdownTimeout = setTimeout(() => {
   182â†’					this.logger.error('Graceful shutdown timeout, forcing exit');
   183â†’					process.exit(1);
   184â†’				}, 30000);
   185â†’
   186â†’				await this.currentOperation;
   187â†’				clearTimeout(shutdownTimeout);
   188â†’			}
   189â†’
   190â†’			this.logger.log('Graceful shutdown completed');
   191â†’			process.exit(0);
   192â†’		} catch (error) {
   193â†’			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   194â†’			process.exit(1);
   195â†’		}
   196â†’	}
   197â†’}
   198â†’

