     1â†’import * as os from 'os';
     2â†’import * as path from 'path';
     3â†’import { Worker, WorkerOptions } from 'worker_threads';
     4â†’
     5â†’import { Logger } from '@nestjs/common';
     6â†’import { Command, CommandRunner, Option } from 'nest-commander';
     7â†’
     8â†’import { rollbar } from '@config/rollbar.config';
     9â†’
    10â†’import { IProductAnnualSalesBase } from '@modules/db/product-annual-sales/types/product-annual-sales.base.interface';
    11â†’import { RenderTrendingResultsService } from '@modules/rest/trending-products/render-trending-results.service';
    12â†’import { TrendingProductsService } from '@modules/rest/trending-products/trending-products.service';
    13â†’
    14â†’import { ProgressBar } from '@utils/progress-bar.util';
    15â†’
    16â†’import { CompleteForecastResult } from '@interfaces/trending-products.interface';
    17â†’
    18â†’import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
    19â†’
    20â†’type ForecastOptions = [string, string, string, string, string];
    21â†’
    22â†’interface WorkerResult {
    23â†’	success: boolean;
    24â†’	results?: CompleteForecastResult[];
    25â†’	error?: string;
    26â†’}
    27â†’
    28â†’@Command({
    29â†’	name: 'forecast-trending-products',
    30â†’	description:
    31â†’		'Analyze historical data and forecast trends for products for the next 7 days',
    32â†’})
    33â†’export class ForecastTrendingProductsCommand extends CommandRunner {
    34â†’	private readonly logger = new Logger(ForecastTrendingProductsCommand.name);
    35â†’	private readonly FORECAST_DAYS = 9;
    36â†’	private readonly PARALLEL_WORKERS = Math.min(os.cpus().length, 8);
    37â†’	private readonly BATCH_SIZE_PER_WORKER = 5;
    38â†’
    39â†’	constructor(
    40â†’		private readonly trendingProductsService: TrendingProductsService,
    41â†’		private readonly renderTrendingResultsService: RenderTrendingResultsService,
    42â†’	) {
    43â†’		super();
    44â†’	}
    45â†’
    46â†’	@Option({
    47â†’		flags: '-s, --start-date [string]',
    48â†’		description: 'Start date for analysis (YYYY-MM-DD)',
    49â†’	})
    50â†’	parseStartDate(val: string): string {
    51â†’		return val;
    52â†’	}
    53â†’
    54â†’	@Option({
    55â†’		flags: '-e, --end-date [string]',
    56â†’		description: 'End date for analysis (YYYY-MM-DD)',
    57â†’	})
    58â†’	parseEndDate(val: string): string {
    59â†’		return val;
    60â†’	}
    61â†’
    62â†’	@Option({
    63â†’		flags: '-p, --products [string]',
    64â†’		description: 'Comma-separated list of style_ids to analyze',
    65â†’	})
    66â†’	parseProducts(val: string): string {
    67â†’		return val;
    68â†’	}
    69â†’
    70â†’	@Option({
    71â†’		flags: '-b, --batch-size [number]',
    72â†’		description: 'Batch size for processing',
    73â†’	})
    74â†’	parseBatchSize(val: string): number {
    75â†’		return parseInt(val, 10);
    76â†’	}
    77â†’
    78â†’	@Option({
    79â†’		flags: '-f, --forecast-days [number]',
    80â†’		description: 'Number of days to forecast (default: 9)',
    81â†’	})
    82â†’	parseForecastDays(val: string): number {
    83â†’		return parseInt(val, 10) || this.FORECAST_DAYS;
    84â†’	}
    85â†’
    86â†’	@CronJobExecution({ jobName: 'forecast-trending-products' })
    87â†’	async run(passedParam: ForecastOptions): Promise<void> {
    88â†’		// TODO: need to use named parameters from options, not as indexed params from passedParam
    89â†’		const startDate = passedParam[0] || this.getDefaultStartDate();
    90â†’		const endDate = passedParam[1] || this.getDefaultEndDate();
    91â†’		const forecastDays = passedParam[4]
    92â†’			? parseInt(passedParam[4], 10)
    93â†’			: this.FORECAST_DAYS;
    94â†’
    95â†’		this.logger.log(`Forecasting trends from ${startDate} to ${endDate}`);
    96â†’
    97â†’		await this.trendingProductsService.invalidateLatestForecasts();
    98â†’
    99â†’		const productsData = await this.trendingProductsService.getStyleIdsInDateRange({
   100â†’			startDate,
   101â†’			endDate,
   102â†’		});
   103â†’
   104â†’		const productIds = productsData.reduce<number[]>((acc, product) => {
   105â†’			if (!acc.includes(product.style_id)) {
   106â†’				acc.push(product.style_id);
   107â†’			}
   108â†’			return acc;
   109â†’		}, []);
   110â†’
   111â†’		this.logger.log(`Found ${productIds.length} products with historical data`);
   112â†’
   113â†’		if (productIds.length === 0) {
   114â†’			this.logger.warn(
   115â†’				'No products found with historical data in the specified date range',
   116â†’			);
   117â†’			return;
   118â†’		}
   119â†’
   120â†’		const totalProducts = productIds.length;
   121â†’
   122â†’		const bar = new ProgressBar({ total: totalProducts });
   123â†’
   124â†’		const allResults = await this.processProductsInParallel({
   125â†’			productIds,
   126â†’			productsData,
   127â†’			startDate,
   128â†’			endDate,
   129â†’			forecastDays,
   130â†’			bar,
   131â†’		});
   132â†’
   133â†’		this.logger.log(
   134â†’			`Forecast completed. Processing ${allResults.length} results for database save.`,
   135â†’		);
   136â†’
   137â†’		const filtered = allResults
   138â†’			.filter((res) => res.predicted_orders.reduce((a, b) => a + b, 0) > 10)
   139â†’			.sort((a, b) => b.trend_score - a.trend_score);
   140â†’
   141â†’		const top30Results = filtered.slice(0, 30);
   142â†’
   143â†’		this.logger.log(
   144â†’			`Generating detailed HTML reports for top ${top30Results.length} trending products...`,
   145â†’		);
   146â†’		await this.renderTrendingResultsService.generateDetailedTrendingProductsReports(
   147â†’			top30Results,
   148â†’		);
   149â†’
   150â†’		this.logger.log('Activating latest predictions...');
   151â†’		await this.trendingProductsService.activateLatestPredictions();
   152â†’
   153â†’		this.logger.log('Forecast and report generation completed successfully');
   154â†’	}
   155â†’
   156â†’	private async processProductsInParallel({
   157â†’		productIds,
   158â†’		productsData,
   159â†’		startDate,
   160â†’		endDate,
   161â†’		forecastDays,
   162â†’		bar,
   163â†’	}: {
   164â†’		productIds: number[];
   165â†’		productsData: IProductAnnualSalesBase[];
   166â†’		startDate: string;
   167â†’		endDate: string;
   168â†’		forecastDays: number;
   169â†’		bar: ProgressBar;
   170â†’	}): Promise<CompleteForecastResult[]> {
   171â†’		const allResults: CompleteForecastResult[] = [];
   172â†’		const batchSize = this.BATCH_SIZE_PER_WORKER;
   173â†’		let processedCount = 0;
   174â†’
   175â†’		const batches: {
   176â†’			styleId: number;
   177â†’			historicalData: IProductAnnualSalesBase[];
   178â†’		}[][] = [];
   179â†’		for (let i = 0; i < productIds.length; i += batchSize) {
   180â†’			const batch = productIds
   181â†’				.slice(i, Math.min(i + batchSize, productIds.length))
   182â†’				.map((styleId) => ({
   183â†’					styleId,
   184â†’					historicalData: productsData.filter((item) => item.style_id === styleId),
   185â†’				}));
   186â†’			batches.push(batch);
   187â†’		}
   188â†’
   189â†’		this.logger.log(
   190â†’			`Processing ${productIds.length} products in ${batches.length} batches using ${this.PARALLEL_WORKERS} workers`,
   191â†’		);
   192â†’
   193â†’		for (let i = 0; i < batches.length; i += this.PARALLEL_WORKERS) {
   194â†’			const batchChunk = batches.slice(
   195â†’				i,
   196â†’				Math.min(i + this.PARALLEL_WORKERS, batches.length),
   197â†’			);
   198â†’
   199â†’			const chunkPromises = batchChunk.map((batch) =>
   200â†’				this.processInWorker({
   201â†’					batch,
   202â†’					startDate,
   203â†’					endDate,
   204â†’					forecastDays,
   205â†’				}),
   206â†’			);
   207â†’
   208â†’			const chunkResults = await Promise.allSettled(chunkPromises);
   209â†’
   210â†’			for (let j = 0; j < chunkResults.length; j++) {
   211â†’				const result = chunkResults[j];
   212â†’				const batch = batchChunk[j];
   213â†’
   214â†’				if (!result || !batch) continue;
   215â†’
   216â†’				if (result.status === 'fulfilled') {
   217â†’					const workerResult = result.value;
   218â†’					if (workerResult.success && workerResult.results) {
   219â†’						allResults.push(...workerResult.results);
   220â†’
   221â†’						if (workerResult.results.length > 0) {
   222â†’							try {
   223â†’								await this.trendingProductsService.saveBatchResults(
   224â†’									workerResult.results,
   225â†’									startDate,
   226â†’									endDate,
   227â†’									forecastDays,
   228â†’								);
   229â†’								this.logger.log(
   230â†’									`Saved ${workerResult.results.length} results to database`,
   231â†’								);
   232â†’							} catch (error) {
   233â†’								const err = error instanceof Error ? error : new Error(String(error));
   234â†’								this.logger.error(`Failed to save batch results: ${err.message}`);
   235â†’								rollbar.error(err, {
   236â†’									operation: 'saveBatchResults',
   237â†’									batchSize: workerResult.results.length,
   238â†’								});
   239â†’							}
   240â†’						}
   241â†’					}
   242â†’				} else {
   243â†’					this.logger.error(`Worker batch failed: ${result.reason}`);
   244â†’					rollbar.error(new Error(`Worker batch failed: ${result.reason}`), {
   245â†’						operation: 'processInWorker',
   246â†’						batchSize: batch.length,
   247â†’					});
   248â†’				}
   249â†’
   250â†’				processedCount += batch.length;
   251â†’				bar.increment(batch.length);
   252â†’				this.logger.log(
   253â†’					`Progress: ${processedCount}/${productIds.length} products processed`,
   254â†’				);
   255â†’			}
   256â†’		}
   257â†’
   258â†’		bar.finish();
   259â†’		return allResults;
   260â†’	}
   261â†’
   262â†’	private processInWorker({
   263â†’		batch,
   264â†’		startDate,
   265â†’		endDate,
   266â†’		forecastDays,
   267â†’	}: {
   268â†’		batch: { styleId: number; historicalData: IProductAnnualSalesBase[] }[];
   269â†’		startDate: string;
   270â†’		endDate: string;
   271â†’		forecastDays: number;
   272â†’	}): Promise<WorkerResult> {
   273â†’		return new Promise((resolve, reject) => {
   274â†’			const isDevelopment = process.env['NODE_ENV'] === 'development';
   275â†’			let workerPath: string;
   276â†’			if (isDevelopment) {
   277â†’				workerPath = path.resolve(__dirname, '..', 'workers', 'forecast-worker.ts');
   278â†’			} else {
   279â†’				workerPath = path.resolve(__dirname, '..', 'workers', 'forecast-worker.js');
   280â†’			}
   281â†’
   282â†’			const workerOptions: WorkerOptions = {
   283â†’				workerData: {
   284â†’					batch,
   285â†’					startDate,
   286â†’					endDate,
   287â†’					forecastDays,
   288â†’				},
   289â†’			};
   290â†’
   291â†’			if (isDevelopment) {
   292â†’				workerOptions.execArgv = [
   293â†’					'-r',
   294â†’					'ts-node/register',
   295â†’					'-r',
   296â†’					'tsconfig-paths/register',
   297â†’				];
   298â†’			}
   299â†’
   300â†’			const worker = new Worker(workerPath, workerOptions);
   301â†’			let resolved = false;
   302â†’
   303â†’			const cleanup = () => {
   304â†’				if (!resolved) {
   305â†’					resolved = true;
   306â†’					worker.terminate().catch(() => {
   307â†’						// Ignore termination errors
   308â†’					});
   309â†’				}
   310â†’			};
   311â†’
   312â†’			const timeout = setTimeout(() => {
   313â†’				cleanup();
   314â†’				reject(new Error('Worker timeout after 60 seconds'));
   315â†’			}, 60000);
   316â†’
   317â†’			worker.on('message', (result: WorkerResult) => {
   318â†’				clearTimeout(timeout);
   319â†’				cleanup();
   320â†’				resolve(result);
   321â†’			});
   322â†’
   323â†’			worker.on('error', (error) => {
   324â†’				clearTimeout(timeout);
   325â†’				cleanup();
   326â†’				reject(error);
   327â†’			});
   328â†’
