   152â†’	private async syncStyleAlternatives(styleId: number): Promise<void> {
   153â†’		try {
   154â†’			const complementsResponse = await this.mmsService.fetchStyleComplements(styleId);
   155â†’
   156â†’			if (!complementsResponse) {
   157â†’				return;
   158â†’			}
   159â†’
   160â†’			const alternativesComplement = complementsResponse.complements.find(
   161â†’				(c) => c.name === 'alternatives',
   162â†’			);
   163â†’
   164â†’			if (!alternativesComplement || alternativesComplement.style_ids.length === 0) {
   165â†’				return;
   166â†’			}
   167â†’
   168â†’			await this.styleAlternativesService.bulkUpsertStyleAlternatives({
   169â†’				styleId,
   170â†’				alternativeStyleIds: alternativesComplement.style_ids,
   171â†’			});
   172â†’
   173â†’			this.logger.debug(
   174â†’				`Synced ${alternativesComplement.style_ids.length} alternatives for style ${styleId}`,
   175â†’			);
   176â†’		} catch (error) {
   177â†’			this.logger.warn(
   178â†’				`Failed to sync alternatives for style ${styleId}: ${error instanceof Error ? error.message : String(error)}`,
   179â†’			);
   180â†’		}
   181â†’	}
   182â†’}
