   249â†’
   250â†’			this.logger.log('Graceful shutdown completed');
   251â†’			process.exit(0);
   252â†’		} catch (error) {
   253â†’			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   254â†’			process.exit(1);
