    41â†’function generateDateRange(startDate: string, endDate: string, count: number): string[] {
    42â†’	const start = new Date(startDate);
    43â†’	const end = new Date(endDate);
    44â†’	const totalDays =
    45â†’		Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24)) + 1;
    46â†’	const step = totalDays / count;
    47â†’
    48â†’	const dates: string[] = [];
    49â†’	for (let i = 0; i < count; i++) {
    50â†’		const currentDate = new Date(start.getTime() + i * step * 24 * 60 * 60 * 1000);
    51â†’		const dateArr = currentDate.toISOString().split('T') as [string, string];
    52â†’		dates.push(dateArr[0]);
    53â†’	}
    54â†’	return dates;
    55â†’}
    56â†’
    57â†’function generateFutureDates(endDate: string, forecastDays: number): string[] {
    58â†’	const dates: string[] = [];
    59â†’	const startDate = new Date(endDate);
    60â†’
    61â†’	for (let i = 1; i <= forecastDays; i++) {
    62â†’		const futureDate = new Date(startDate);
    63â†’		futureDate.setDate(startDate.getDate() + i);
    64â†’		const dateArr = futureDate.toISOString().split('T') as [string, string];
    65â†’		dates.push(dateArr[0]);
    66â†’	}
    67â†’
    68â†’	return dates;
    69â†’}
