    71â†’function calculateSeasonalComponent({
    72â†’	values,
    73â†’	period,
    74â†’	harmonics,
    75â†’}: {
    76â†’	values: number[];
    77â†’	period: number;
    78â†’	harmonics: number;
    79â†’}): number[] {
    80â†’	const n = values.length;
    81â†’	if (n < period) {
    82â†’		return new Array(n).fill(0) as number[];
    83â†’	}
    84â†’
    85â†’	try {
    86â†’		const coefficients = MathematicalFunctions.fourierCoefficients({
    87â†’			values,
    88â†’			period,
    89â†’			harmonics,
    90â†’			precision: null,
    91â†’		});
    92â†’
    93â†’		const seasonal = MathematicalFunctions.reconstructFourierSeries({
    94â†’			period,
    95â†’			harmonics,
    96â†’			a: coefficients.a,
    97â†’			b: coefficients.b,
    98â†’			length: n,
    99â†’		});
   100â†’
   101â†’		return seasonal;
   102â†’	} catch {
   103â†’		return values.map((_, index) => {
   104â†’			const cyclePosition = index % Math.max(1, Math.floor(period));
   105â†’			const seasonalIndex = Math.min(cyclePosition, values.length - 1);
   106â†’			return values[seasonalIndex] ? values[seasonalIndex] * 0.1 : 0;
   107â†’		});
   108â†’	}
   109â†’}
