   111â†’function calculateTrendComponent({
   112â†’	values,
   113â†’	changePoints,
   114â†’	startDate,
   115â†’	endDate,
   116â†’}: {
   117â†’	values: number[];
   118â†’	changePoints: number[];
   119â†’	startDate: string;
   120â†’	endDate: string;
   121â†’}): number[] {
   122â†’	const n = values.length;
   123â†’	if (n === 0) return [];
   124â†’
   125â†’	const dates = generateDateRange(startDate, endDate, n);
   126â†’
   127â†’	if (changePoints.length === 0) {
   128â†’		return MathematicalFunctions.calculateTrend({ values, dates });
   129â†’	}
   130â†’
   131â†’	const trend = new Array(n).fill(0) as number[];
   132â†’	const segments = [0, ...changePoints, n];
   133â†’
   134â†’	for (let i = 0; i < segments.length - 1; i++) {
   135â†’		const start = segments[i] as unknown as number;
   136â†’		const end = segments[i + 1] as unknown as number;
   137â†’		const segmentValues = values.slice(start, end);
   138â†’		const segmentDates = dates.slice(start, end);
   139â†’
   140â†’		if (segmentValues.length > 1) {
   141â†’			const segmentTrend = MathematicalFunctions.calculateTrend({
   142â†’				values: segmentValues,
   143â†’				dates: segmentDates,
   144â†’			});
   145â†’
   146â†’			for (let j = 0; j < segmentTrend.length; j++) {
   147â†’				trend[start + j] = segmentTrend[j] as unknown as number;
   148â†’			}
   149â†’		} else if (segmentValues.length === 1) {
   150â†’			trend[start] = segmentValues[0] as unknown as number;
   151â†’		}
   152â†’	}
   153â†’
   154â†’	return trend;
   155â†’}
