   157â†’function extendSeasonalComponent(
   158â†’	component: number[],
   159â†’	period: number,
   160â†’	harmonics: number,
   161â†’	historicalLength: number,
   162â†’	forecastDates: string[],
   163â†’	endDate: string,
   164â†’): number[] {
   165â†’	if (component.length === 0) return Array(forecastDates.length).fill(0) as number[];
   166â†’
   167â†’	try {
   168â†’		const coefficients = MathematicalFunctions.fourierCoefficients({
   169â†’			values: component,
   170â†’			period,
   171â†’			harmonics,
   172â†’			precision: null,
   173â†’		});
   174â†’
   175â†’		const forecastValues: number[] = [];
   176â†’		const endDateObj = new Date(endDate);
   177â†’
   178â†’		for (const forecastDate of forecastDates) {
   179â†’			const forecastDateObj = new Date(forecastDate);
   180â†’
   181â†’			const daysDiff = Math.floor(
   182â†’				(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   183â†’			);
   184â†’
   185â†’			const cyclePosition = (historicalLength + daysDiff) % period;
   186â†’			const singlePointSeries = MathematicalFunctions.reconstructFourierSeries({
   187â†’				period,
   188â†’				harmonics,
   189â†’				a: coefficients.a,
   190â†’				b: coefficients.b,
   191â†’				length: Math.ceil(cyclePosition) + 1,
   192â†’				a0: 0,
   193â†’			});
   194â†’
   195â†’			const seasonalValue = singlePointSeries[Math.floor(cyclePosition)] ?? 0;
   196â†’			forecastValues.push(seasonalValue);
   197â†’		}
   198â†’
   199â†’		return forecastValues;
   200â†’	} catch {
   201â†’		return forecastDates.map((forecastDate) => {
   202â†’			const endDateObj = new Date(endDate);
   203â†’			const forecastDateObj = new Date(forecastDate);
   204â†’			const daysDiff = Math.floor(
   205â†’				(forecastDateObj.getTime() - endDateObj.getTime()) / (1000 * 60 * 60 * 24),
   206â†’			);
   207â†’			const flooredPeriod = Math.max(1, Math.floor(period));
   208â†’			const cyclePosition = (historicalLength + daysDiff) % flooredPeriod;
   209â†’			const historicalIndex = Math.min(cyclePosition, component.length - 1);
   210â†’			return component[historicalIndex] ?? 0;
   211â†’		});
   212â†’	}
   213â†’}
