   215â†’function extendTrendComponent(trendComponent: number[], forecastDays: number): number[] {
   216â†’	if (trendComponent.length < 2) return Array(forecastDays).fill(0) as number[];
   217â†’
   218â†’	const recentTrendPoints = Math.min(30, trendComponent.length);
   219â†’	const recentTrend = trendComponent.slice(-recentTrendPoints);
   220â†’
   221â†’	const x = Array.from({ length: recentTrend.length }, (_, i) => i);
   222â†’	const regression = MathematicalFunctions.linearRegression({ x, y: recentTrend });
   223â†’
   224â†’	const lastValue = trendComponent[trendComponent.length - 1] ?? 0;
   225â†’	const trendSlope = regression.slope;
   226â†’
   227â†’	return Array(forecastDays)
   228â†’		.fill(0)
   229â†’		.map((_, i) => {
   230â†’			const decay = Math.exp(-0.02 * i);
   231â†’			return lastValue + trendSlope * (i + 1) * decay;
   232â†’		});
   233â†’}
   234â†’
   235â†’function extendResidualsComponent({
   236â†’	smoothedResidualsArr,
   237â†’	forecastDays,
   238â†’	endDate,
   239â†’}: {
   240â†’	smoothedResidualsArr: number[];
   241â†’	forecastDays: number;
   242â†’	endDate: string;
   243â†’}): number[] {
   244â†’	if (smoothedResidualsArr.length === 0 || forecastDays <= 0) {
   245â†’		return Array(forecastDays).fill(0) as number[];
   246â†’	}
   247â†’
   248â†’	const twoWeeksLength = 7;
   249â†’	const trendLength = Math.min(twoWeeksLength, smoothedResidualsArr.length);
   250â†’	const recentResiduals = smoothedResidualsArr.slice(-trendLength);
   251â†’
   252â†’	const endDateObj = new Date(endDate);
   253â†’	const dates = recentResiduals.map((_, i) => {
   254â†’		const date = new Date(endDateObj);
   255â†’		date.setDate(endDateObj.getDate() - (trendLength - i - 1));
   256â†’		const dateArr = date.toISOString().split('T') as [string, string];
   257â†’		return dateArr[0];
   258â†’	});
   259â†’
   260â†’	const trendValues = MathematicalFunctions.calculateTrend({
   261â†’		values: recentResiduals,
   262â†’		dates,
   263â†’	});
   264â†’
   265â†’	if (trendValues.length === 0) {
   266â†’		return Array(forecastDays).fill(0) as number[];
   267â†’	}
   268â†’
   269â†’	const x = Array.from({ length: recentResiduals.length }, (_, i) => i);
   270â†’	const regression = MathematicalFunctions.linearRegression({ x, y: recentResiduals });
   271â†’
   272â†’	const lastIndex = recentResiduals.length - 1;
   273â†’	return Array(forecastDays)
   274â†’		.fill(0)
   275â†’		.map((_, i) => {
   276â†’			return regression.slope * (lastIndex + i + 1) + regression.intercept;
   277â†’		});
   278â†’}
