   280â†’function createComprehensiveForecast({
   281â†’	yearlyComponent,
   282â†’	monthlyComponent,
   283â†’	weeklyComponent,
   284â†’	quarterlyComponent,
   285â†’	trendComponent,
   286â†’	smoothedResidualsArr,
   287â†’	historicalLength,
   288â†’	forecastDays,
   289â†’	endDate,
   290â†’}: {
   291â†’	yearlyComponent: number[];
   292â†’	monthlyComponent: number[];
   293â†’	weeklyComponent: number[];
   294â†’	quarterlyComponent: number[];
   295â†’	trendComponent: number[];
   296â†’	smoothedResidualsArr: number[];
