   339â†’	);
   340â†’
   341â†’	const extendedResiduals = extendResidualsComponent({
   342â†’		smoothedResidualsArr,
   343â†’		forecastDays,
   344â†’		endDate,
   345â†’	});
   346â†’
   347â†’	const extendedTrend = extendTrendComponent(trendComponent, forecastDays);
   348â†’
   349â†’	const forecastValues = Array(forecastDays)
   350â†’		.fill(0)
   351â†’		.map((_, i) => {
   352â†’			const yearly = extendedYearly[i] ?? 0;
   353â†’			const monthly = extendedMonthly[i] ?? 0;
   354â†’			const weekly = extendedWeekly[i] ?? 0;
   355â†’			const quarterly = extendedQuarterly[i] ?? 0;
