   376â†’function forecastStyleTrend({
   377â†’	styleId,
   378â†’	historicalData,
   379â†’	startDate,
   380â†’	endDate,
   381â†’	forecastDays,
   382â†’}: {
   383â†’	styleId: number;
   384â†’	historicalData: IProductAnnualSalesBase[];
   385â†’	startDate: string;
   386â†’	endDate: string;
   387â†’	forecastDays: number;
   388â†’}): CompleteForecastResult | null {
   389â†’	try {
   390â†’		const startDateObj = new Date(startDate);
   391â†’		const endDateObj = new Date(endDate);
   392â†’		const startYear = startDateObj.getFullYear();
   393â†’		const endYear = endDateObj.getFullYear();
   394â†’		const endDateDayNumber = getDayOfYear(endDateObj);
   395â†’
   396â†’		const totalExpectedDays =
   397â†’			Math.floor(
   398â†’				(endDateObj.getTime() - startDateObj.getTime()) / (1000 * 60 * 60 * 24),
   399â†’			) + 1;
   400â†’
   401â†’		const dataByYear = new Map<number, number[]>();
   402â†’		for (const data of historicalData) {
   403â†’			dataByYear.set(data.year, data.daily_orders);
   404â†’		}
   405â†’
   406â†’		const purchasesArr: number[] = [];
   407â†’
   408â†’		for (let year = startYear; year <= endYear; year++) {
   409â†’			const yearData = dataByYear.get(year);
   410â†’
   411â†’			if (!yearData) {
   412â†’				if (year === endYear) {
   413â†’					purchasesArr.push(...(new Array(endDateDayNumber).fill(0) as number[]));
   414â†’				} else {
   415â†’					const daysInYear =
   416â†’						new Date(year, 11, 31).getDate() === 31 &&
   417â†’						new Date(year, 1, 29).getDate() === 29
   418â†’							? 366
   419â†’							: 365;
   420â†’					purchasesArr.push(...(new Array(daysInYear).fill(0) as number[]));
   421â†’				}
   422â†’			} else {
   423â†’				if (year === endYear) {
   424â†’					purchasesArr.push(...yearData.slice(0, endDateDayNumber));
   425â†’				} else {
   426â†’					purchasesArr.push(...yearData);
   427â†’				}
   428â†’			}
   429â†’		}
   430â†’
   431â†’		if (purchasesArr.length < totalExpectedDays) {
   432â†’			const missingDays = totalExpectedDays - purchasesArr.length;
   433â†’			purchasesArr.push(...(new Array(missingDays).fill(0) as number[]));
   434â†’		} else if (purchasesArr.length > totalExpectedDays) {
   435â†’			purchasesArr.splice(totalExpectedDays);
   436â†’		}
   437â†’
   438â†’		const smoothedPurchasesArr = MathematicalFunctions.exponentialSmoothing({
   439â†’			values: purchasesArr,
   440â†’			alpha: 0.1,
   441â†’		});
   442â†’
   443â†’		const harmonics = getHarmonicsByObservationsCount({
   444â†’			observations: smoothedPurchasesArr.length,
   445â†’		});
   446â†’
   447â†’		const changes = MathematicalFunctions.changePointDetection({
   448â†’			values: smoothedPurchasesArr,
   449â†’			significance: 0.02,
   450â†’			penalty: 0.1,
   451â†’			minSegmentLength: 40,
   452â†’		});
   453â†’
   454â†’		const yearlyComponent = calculateSeasonalComponent({
   455â†’			values: smoothedPurchasesArr,
   456â†’			period: 365,
   457â†’			harmonics,
   458â†’		});
   459â†’
   460â†’		const monthlyComponent = calculateSeasonalComponent({
   461â†’			values: smoothedPurchasesArr,
   462â†’			period: 30,
   463â†’			harmonics,
   464â†’		});
   465â†’
   466â†’		const weeklyComponent = calculateSeasonalComponent({
   467â†’			values: smoothedPurchasesArr,
   468â†’			period: 7,
   469â†’			harmonics,
   470â†’		});
   471â†’
   472â†’		const quarterlyComponent = calculateSeasonalComponent({
   473â†’			values: smoothedPurchasesArr,
   474â†’			period: 91,
   475â†’			harmonics,
   476â†’		});
   477â†’
   478â†’		const trendComponent = calculateTrendComponent({
   479â†’			values: smoothedPurchasesArr,
   480â†’			changePoints: changes.changePoints,
   481â†’			startDate: startDate,
   482â†’			endDate: endDate,
   483â†’		});
   484â†’
   485â†’		const residuals = purchasesArr.map((val, i) => {
   486â†’			const trend = trendComponent[i] ?? 0;
   487â†’			const yearly = yearlyComponent[i] ?? 0;
   488â†’			const monthly = monthlyComponent[i] ?? 0;
   489â†’			const weekly = weeklyComponent[i] ?? 0;
   490â†’			const quarterly = quarterlyComponent[i] ?? 0;
   491â†’			return val - (trend + yearly + monthly + weekly + quarterly);
   492â†’		});
   493â†’
   494â†’		const smoothedResidualsArr = MathematicalFunctions.exponentialSmoothing({
   495â†’			values: residuals,
   496â†’			alpha: 0.1,
   497â†’		});
   498â†’
   499â†’		const comprehensiveForecast = createComprehensiveForecast({
   500â†’			yearlyComponent,
   501â†’			monthlyComponent,
   502â†’			weeklyComponent,
   503â†’			quarterlyComponent,
   504â†’			trendComponent,
   505â†’			smoothedResidualsArr,
   506â†’			historicalLength: purchasesArr.length,
   507â†’			forecastDays,
   508â†’			endDate,
   509â†’			purchasesArr,
   510â†’		});
   511â†’
   512â†’		const historicalWindow = 14;
   513â†’		const historicalOrders = purchasesArr.slice(-historicalWindow);
   514â†’
   515â†’		const trendingScoreData = {
   516â†’			historicalOrders,
   517â†’			forecastedOrders: comprehensiveForecast.forecastValues,
   518â†’			trendComponent,
   519â†’		};
   520â†’
   521â†’		const trendingResult =
   522â†’			TrendingScoreCalculator.calculateTrendingScore(trendingScoreData);
   523â†’
   524â†’		const trendScore = trendingResult.trendScore;
   525â†’		let trendingReason = trendingResult.isSignificant
   526â†’			? `Statistical trend detected (p=${trendingResult.pValue.toFixed(3)}, effect=${trendingResult.effectSize.toFixed(2)})`
   527â†’			: 'No significant trend detected';
   528â†’
   529â†’		if (trendingResult.momentum > 0) {
   530â†’			trendingReason += ', accelerating';
   531â†’		} else if (trendingResult.momentum < 0) {
   532â†’			trendingReason += ', decelerating';
   533â†’		}
   534â†’
   535â†’		const forecastResult: CompleteForecastResult = {
   536â†’			style_id: styleId,
   537â†’			forecast_dates: comprehensiveForecast.forecastDates,
   538â†’			predicted_orders: comprehensiveForecast.forecastValues,
   539â†’			trend_score: Math.round(trendScore * 100) / 100,
   540â†’			trending_reason: trendingReason,
   541â†’			purchasesArr,
   542â†’			smoothedPurchasesArr,
   543â†’			yearlyComponent,
   544â†’			monthlyComponent,
   545â†’			weeklyComponent,
   546â†’			quarterlyComponent,
   547â†’			trendComponent,
   548â†’			smoothedResidualsArr,
   549â†’			comprehensiveForecast,
   550â†’			changes,
   551â†’			startDate,
   552â†’			endDate,
   553â†’		};
   554â†’
   555â†’		return forecastResult;
   556â†’	} catch {
   557â†’		return null;
   558â†’	}
   559â†’}
