   561â†’function processBatch(data: WorkerData): WorkerResult {
   562â†’	try {
   563â†’		const results: CompleteForecastResult[] = [];
   564â†’
   565â†’		for (const item of data.batch) {
   566â†’			const result = forecastStyleTrend({
   567â†’				styleId: Number(item.styleId),
   568â†’				historicalData: item.historicalData,
   569â†’				startDate: data.startDate,
