     1â†’export interface ConcurrencyPoolOptions<T, R> {
     2â†’	items: T[];
     3â†’	concurrency: number;
     4â†’	handler: (item: T) => Promise<R>;
     5â†’	onItemComplete?: (result: R, item: T) => void;
     6â†’	onItemError?: (error: unknown, item: T) => void;
     7â†’}
     8â†’
     9â†’export interface ConcurrencyPoolResult<R> {
    10â†’	results: R[];
    11â†’	errors: { error: unknown; index: number }[];
    12â†’}
    13â†’
    14â†’export async function runWithConcurrencyLimit<T, R>({
    15â†’	items,
    16â†’	concurrency,
    17â†’	handler,
    18â†’	onItemComplete,
    19â†’	onItemError,
    20â†’}: ConcurrencyPoolOptions<T, R>): Promise<ConcurrencyPoolResult<R>> {
    21â†’	const results: R[] = [];
    22â†’	const errors: { error: unknown; index: number }[] = [];
    23â†’	let currentIndex = 0;
    24â†’
    25â†’	async function processNext(): Promise<void> {
    26â†’		while (currentIndex < items.length) {
    27â†’			const index = currentIndex++;
    28â†’			const item = items[index];
    29â†’
    30â†’			if (item === undefined) {
    31â†’				continue;
    32â†’			}
    33â†’
    34â†’			try {
    35â†’				const result = await handler(item);
    36â†’				results.push(result);
    37â†’				onItemComplete?.(result, item);
    38â†’			} catch (error) {
    39â†’				errors.push({ error, index });
    40â†’				onItemError?.(error, item);
    41â†’			}
    42â†’		}
    43â†’	}
    44â†’
    45â†’	const workers = Array.from({ length: Math.min(concurrency, items.length) }, () =>
    46â†’		processNext(),
    47â†’	);
    48â†’
    49â†’	await Promise.all(workers);
    50â†’
    51â†’	return { results, errors };
    52â†’}
