    54â†’export async function* generateWithConcurrencyLimit<T, R>({
    55â†’	items,
    56â†’	concurrency,
    57â†’	handler,
    58â†’}: Omit<ConcurrencyPoolOptions<T, R>, 'onItemComplete' | 'onItemError'>): AsyncGenerator<
    59â†’	{ result: R; item: T } | { error: unknown; item: T }
    60â†’> {
    61â†’	const queue: (
    62â†’		| { type: 'result'; result: R; item: T }
    63â†’		| { type: 'error'; error: unknown; item: T }
    64â†’	)[] = [];
    65â†’	let resolveWaiting: (() => void) | null = null;
    66â†’	let currentIndex = 0;
    67â†’	let activeWorkers = 0;
    68â†’	let done = false;
    69â†’
    70â†’	async function processNext(): Promise<void> {
    71â†’		while (currentIndex < items.length) {
    72â†’			const index = currentIndex++;
    73â†’			const item = items[index];
    74â†’
    75â†’			if (item === undefined) {
    76â†’				continue;
    77â†’			}
    78â†’
    79â†’			try {
    80â†’				const result = await handler(item);
    81â†’				queue.push({ type: 'result', result, item });
    82â†’			} catch (error) {
    83â†’				queue.push({ type: 'error', error, item });
    84â†’			}
    85â†’
    86â†’			if (resolveWaiting) {
    87â†’				resolveWaiting();
    88â†’				resolveWaiting = null;
    89â†’			}
    90â†’		}
    91â†’
    92â†’		activeWorkers--;
    93â†’		if (activeWorkers === 0) {
    94â†’			done = true;
    95â†’			if (resolveWaiting) {
    96â†’				resolveWaiting();
    97â†’				resolveWaiting = null;
    98â†’			}
    99â†’		}
   100â†’	}
   101â†’
   102â†’	activeWorkers = Math.min(concurrency, items.length);
   103â†’	for (let i = 0; i < activeWorkers; i++) {
   104â†’		void processNext();
   105â†’	}
   106â†’
   107â†’	while (!done || queue.length > 0) {
   108â†’		if (queue.length === 0 && !done) {
   109â†’			await new Promise<void>((resolve) => {
   110â†’				resolveWaiting = resolve;
   111â†’			});
   112â†’		}
   113â†’
   114â†’		while (queue.length > 0) {
   115â†’			const entry = queue.shift();
   116â†’			if (entry) {
   117â†’				if (entry.type === 'result') {
   118â†’					yield { result: entry.result, item: entry.item };
   119â†’				} else {
   120â†’					yield { error: entry.error, item: entry.item };
   121â†’				}
   122â†’			}
   123â†’		}
   124â†’	}
