    45â†’				` ${this.current}/?`;
    46â†’
    47â†’			if (metadata?.['updatedCount'] !== undefined) {
    48â†’				bar += ` - Updated: ${metadata['updatedCount']}`;
    49â†’			}
    50â†’
    51â†’			this.draw(bar);
    52â†’		}
    53â†’	}
    54â†’
    55â†’	increment(by = 1, metadata?: Record<string, string | number>): void {
    56â†’		this.update(this.current + by, metadata);
    57â†’	}
    58â†’
