    66â†’			} else {
    67â†’				process.stdout.write(bar + '\n');
    68â†’			}
    69â†’			this.lastDraw = bar;
    70â†’		}
    71â†’	}
    72â†’
    73â†’	finish(): void {
    74â†’		if (this.total === 0) {
    75â†’			process.stdout.write('\n');
    76â†’		}
    77â†’	}
    78â†’}
