     6â†’
     7â†’export interface CronJobExecutionOptions {
     8â†’	jobName: string;
     9â†’	context?: Record<string, unknown>;
    10â†’}
    11â†’
    12â†’function formatDuration(ms: number): string {
    13â†’	const seconds = Math.floor(ms / 1000);
    14â†’	const minutes = Math.floor(seconds / 60);
    15â†’	const hours = Math.floor(minutes / 60);
    16â†’
    17â†’	if (hours > 0) {
    18â†’		return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
    19â†’	}
    20â†’
    21â†’	if (minutes > 0) {
    22â†’		return `${minutes}m ${seconds % 60}s`;
    23â†’	}
    24â†’
    25â†’	return `${seconds}s`;
    26â†’}
    27â†’
    28â†’export function CronJobExecution(options: CronJobExecutionOptions): MethodDecorator {
    29â†’	const { jobName, context = {} } = options;
    30â†’
    31â†’	return function (
    32â†’		target: unknown,
    33â†’		_propertyKey: string | symbol,
    34â†’		descriptor: PropertyDescriptor,
    35â†’	) {
    36â†’		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
    37â†’		const className = (target as { constructor: { name: string } }).constructor.name;
    38â†’		const logger = new Logger(className);
    39â†’
    40â†’		descriptor.value = async function (...args: unknown[]) {
    41â†’			const startTime = performance.now();
    42â†’
    43â†’			logger.log(`Starting ${jobName}`);
    44â†’			rollbar.info(`Starting ${jobName}`, {
    45â†’				command: jobName,
    46â†’				...context,
    47â†’			});
    48â†’
    49â†’			try {
    50â†’				await originalMethod.apply(this, args);
    51â†’
    52â†’				const executionTimeMs = performance.now() - startTime;
    53â†’
    54â†’				logger.log(`${jobName} completed. Duration: ${formatDuration(executionTimeMs)}`);
    55â†’				rollbar.info(`${jobName} completed`, {
    56â†’					command: jobName,
    57â†’					executionTimeMs,
    58â†’					executionTimeFormatted: formatDuration(executionTimeMs),
    59â†’					...context,
    60â†’				});
    61â†’
    62â†’				rollbar.wait(() => {
    63â†’					process.exit(0);
    64â†’				});
    65â†’			} catch (error) {
    66â†’				const executionTimeMs = performance.now() - startTime;
    67â†’
    68â†’				logger.error(
    69â†’					`${jobName} failed after ${formatDuration(executionTimeMs)}:`,
    70â†’					(error as Error).stack,
    71â†’				);
    72â†’				rollbar.error(`${jobName} failed`, {
    73â†’					command: jobName,
    74â†’					executionTimeMs,
    75â†’					executionTimeFormatted: formatDuration(executionTimeMs),
    76â†’					error: error instanceof Error ? error.message : String(error),
    77â†’					...context,
    78â†’				});
    79â†’
    80â†’				rollbar.wait(() => {
    81â†’					process.exit(1);
    82â†’				});
    83â†’			}
    84â†’		};
    85â†’
    86â†’		return descriptor;
    87â†’	};
    88â†’}
